import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { toast, ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import Header from './Header';

const API_ENDPOINTS = [
  {
    name: 'Save RFID Transaction Details',
    endpoint: 'SaveRFIDTransactionDetails',
    method: 'POST',
    description: 'Save new RFID transaction details to the inventory stock table.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: false,
    icon: 'fas fa-save',
    highlight: 'primary',
    behavioralCases: [
      {
        title: 'Case 1: RFID Number Already Exists with Status "ApiActive" or "Active"',
        description: 'The existing record will be updated with the new details (category, product, weight, item code, box details, etc.)'
      },
      {
        title: 'Case 2: RFID Number Does Not Exist in tblLabelledStock',
        description: 'A new record will be inserted with the provided details.'
      },
      {
        title: 'Case 3: RFID Number Exists but with a Different Status',
        description: 'If the barcode exists but has a different status (not "ApiActive" or "Active"), the API will create a new record instead of updating.'
      }
    ],
    sampleBody: {
      "ClientCode": "", // Will be filled dynamically
      "RFIDNumber": "RFID123456789",
      "ItemCode": "ITEM001",
      "CategoryId": 1,
      "ProductId": 2,
      "DesignId": 3,
      "PurityId": 4,
      "GrossWeight": "10.50",
      "NetWeight": "9.80",
      "BoxNumber": "BOX001",
      "Status": "ApiActive"
    }
  },
  {
    name: 'Update RFID Transaction Details',
    endpoint: 'UpdateRFIDTransactionDetails',
    method: 'POST',
    description: 'Update the status of the product to Active or Sold based on the RFID Number.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: false,
    icon: 'fas fa-edit',
    highlight: 'info',
    behavioralCases: [
      {
        title: 'Case 1: RFID Number Already Exists with Status "ApiActive" or "Active"',
        description: 'The existing record will be updated with the new details (category, product, weight, item code, box details, etc.)'
      },
      {
        title: 'Case 2: RFID Number Does Not Exist in tblLabelledStock',
        description: 'A new record will be inserted with the provided details.'
      },
      {
        title: 'Case 3: RFID Number Exists but with a Different Status',
        description: 'If the barcode exists but has a different status (not "ApiActive" or "Active"), the API will create a new record instead of updating.'
      }
    ],
    sampleBody: {
      "ClientCode": "", // Will be filled dynamically
      "RFIDNumber": "RFID123456789",
      "Status": "Sold" // Can be "Sold" or "Active"
    }
  },
  {
    name: 'Get RFID Transaction Details',
    endpoint: 'GetRFIDTransactionDetails',
    method: 'POST',
    description: 'Retrieve all records from the inventory stock table.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: false,
    icon: 'fas fa-search',
    highlight: 'primary',
    behavioralCases: [
      {
        title: 'Case 1: RFID Number Already Exists with Status "ApiActive" or "Active"',
        description: 'The existing record will be updated with the new details (category, product, weight, item code, box details, etc.)'
      },
      {
        title: 'Case 2: RFID Number Does Not Exist in tblLabelledStock',
        description: 'A new record will be inserted with the provided details.'
      },
      {
        title: 'Case 3: RFID Number Exists but with a Different Status',
        description: 'If the barcode exists but has a different status (not "ApiActive" or "Active"), the API will create a new record instead of updating.'
      }
    ],
    sampleBody: {
      "ClientCode": "" // Will be filled dynamically
    }
  },
  {
    name: 'Delete Labelled Stock Items',
    endpoint: 'DeleteLabelledStockItems',
    method: 'POST',
    description: 'Delete one or more items using ClientCode, RFID Number, or ItemCode.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: true,
    icon: 'fas fa-trash',
    highlight: 'danger',
    behavioralCases: [
      {
        title: 'Case 1: RFID Number Already Exists with Status "ApiActive" or "Active"',
        description: 'The existing record will be updated with the new details (category, product, weight, item code, box details, etc.)'
      },
      {
        title: 'Case 2: RFID Number Does Not Exist in tblLabelledStock',
        description: 'A new record will be inserted with the provided details.'
      },
      {
        title: 'Case 3: RFID Number Exists but with a Different Status',
        description: 'If the barcode exists but has a different status (not "ApiActive" or "Active"), the API will create a new record instead of updating.'
      }
    ],
    sampleBody: {
      "ClientCode": "", // Will be filled dynamically
      "RFIDNumbers": ["RFID123456789", "RFID987654321"],
      "ItemCodes": ["ITEM001", "ITEM002"]
    }
  }
];

const Dashboard = () => {
  const [selectedApi, setSelectedApi] = useState(null);
  const [requestBody, setRequestBody] = useState('');
  const [response, setResponse] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [userInfo, setUserInfo] = useState(null);
  const [token, setToken] = useState('');
  const [dashboardError, setDashboardError] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    const storedToken = localStorage.getItem('token');
    const storedUserInfo = localStorage.getItem('userInfo');
    
    if (!storedToken) {
      setDashboardError('No token found. Please login again.');
      navigate('/login');
      return;
    }

    // Validate token and extract client code
    try {
      const tokenData = JSON.parse(atob(storedToken.split('.')[1]));
      console.log('Dashboard tokenData:', tokenData);
      if (!tokenData.ClientCode) {
        setDashboardError('Invalid token: No client code found.');
        throw new Error('Invalid token: No client code found');
      }
      setToken(storedToken);
      
      if (storedUserInfo) {
        const parsedUserInfo = JSON.parse(storedUserInfo);
        if (parsedUserInfo.ClientCode !== tokenData.ClientCode) {
          console.warn('Stored client code does not match token. Using token data.');
          parsedUserInfo.ClientCode = tokenData.ClientCode;
          localStorage.setItem('userInfo', JSON.stringify(parsedUserInfo));
        }
        setUserInfo(parsedUserInfo);
      } else {
        const userInfo = {
          Username: tokenData.sub,
          ClientCode: tokenData.ClientCode
        };
        localStorage.setItem('userInfo', JSON.stringify(userInfo));
        setUserInfo(userInfo);
      }
    } catch (err) {
      console.error('Token validation error:', err);
      setDashboardError('Token validation error: ' + err.message);
      localStorage.removeItem('token');
      localStorage.removeItem('userInfo');
      navigate('/login');
    }
  }, [navigate]);

  const handleApiSelect = (api) => {
    setSelectedApi(api);
    let sampleBodyCopy = JSON.parse(JSON.stringify(api.sampleBody));
    
    // Handle both array and object request bodies
    if (Array.isArray(sampleBodyCopy)) {
      sampleBodyCopy = sampleBodyCopy.map(item => ({
        ...item,
        ClientCode: userInfo?.ClientCode || ''
      }));
    } else {
      sampleBodyCopy = {
        ...sampleBodyCopy,
        ClientCode: userInfo?.ClientCode || ''
      };
    }
    
    setRequestBody(JSON.stringify(sampleBodyCopy, null, 2));
    setResponse('');
    setError('');
  };

  const isAuthenticated = !!token && !!userInfo?.ClientCode;

  const handleSendRequest = async () => {
    if (!selectedApi) return;
    if (!isAuthenticated) {
      setError('You must be logged in to test the API.');
      toast.error('You must be logged in to test the API.', {
        theme: 'colored',
        style: { fontFamily: 'Poppins, Montserrat, Arial, sans-serif' }
      });
      return;
    }
    setLoading(true);
    setError('');
    setResponse('');
    try {
      const config = {
        headers: {
          'Content-Type': 'application/json'
        }
      };
      if (selectedApi.authRequired) {
        if (!token) {
          throw new Error('Authentication token is required for this endpoint');
        }
        config.headers['Authorization'] = `Bearer ${token}`;
      }
      const url = `${selectedApi.baseUrl}/${selectedApi.endpoint}`;
      let parsedBody;
      try {
        parsedBody = JSON.parse(requestBody);
      } catch (e) {
        throw new Error('Invalid JSON in request body');
      }
      if (!parsedBody.ClientCode) {
        throw new Error('ClientCode is required');
      }
      const result = await axios.post(url, parsedBody, config);
      if (result.data.Status === false) {
        throw new Error(result.data.Message || 'Operation failed');
      }
      setResponse(JSON.stringify(result.data, null, 2));
      toast.success(result.data.Message || 'API request successful!', {
        theme: 'colored',
        style: { fontFamily: 'Poppins, Montserrat, Arial, sans-serif' }
      });
    } catch (err) {
      const errorMessage = err.response?.data?.Message || err.message || 'An error occurred while making the request.';
      setError(errorMessage);
      toast.error(errorMessage, {
        theme: 'colored',
        style: { fontFamily: 'Poppins, Montserrat, Arial, sans-serif' }
      });
      if (err.response?.status === 401) {
        toast.error('Authentication failed. Please login again.', {
          theme: 'colored',
          style: { fontFamily: 'Poppins, Montserrat, Arial, sans-serif' }
        });
        localStorage.removeItem('token');
        localStorage.removeItem('userInfo');
        navigate('/login');
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: '#f6f7fb',
      fontFamily: 'Poppins, Montserrat, Arial, sans-serif',
      padding: 0
    }}>
      <Header userInfo={userInfo} />
      <ToastContainer />
      {dashboardError && (
        <div className="alert alert-danger m-4">
          <i className="fas fa-exclamation-circle me-2"></i>
          {dashboardError}
        </div>
      )}
      <div className="container py-4">
        <div className="row">
          <div className="col-md-4 mb-4">
            <div className="card border-0 shadow-sm" style={{ background: '#fff', borderRadius: 14 }}>
              <div className="card-header bg-white border-0" style={{ borderTopLeftRadius: 14, borderTopRightRadius: 14 }}>
                <h5 className="mb-0" style={{ fontFamily: 'Poppins, Montserrat, Arial, sans-serif', color: '#2563eb' }}>
                  <i className="fas fa-list me-2 text-primary"></i>
                  API Endpoints
                </h5>
              </div>
              <div className="list-group list-group-flush">
                {API_ENDPOINTS.map((api, index) => (
                  <button
                    key={index}
                    className={`list-group-item list-group-item-action d-flex align-items-center ${selectedApi?.endpoint === api.endpoint ? 'active' : ''}`}
                    style={{
                      border: 'none',
                      background: selectedApi?.endpoint === api.endpoint ? 'linear-gradient(90deg, #2563eb 0%, #60a5fa 100%)' : 'transparent',
                      color: selectedApi?.endpoint === api.endpoint ? '#fff' : '#2563eb',
                      fontWeight: 500,
                      fontFamily: 'Poppins, Montserrat, Arial, sans-serif',
                      transition: 'background 0.2s, color 0.2s',
                      marginBottom: 2,
                      borderRadius: 8
                    }}
                    onClick={() => handleApiSelect(api)}
                  >
                    <i className={`${api.icon} me-2 text-${api.highlight === 'danger' ? 'danger' : 'primary'}`}></i>
                    {api.name}
                  </button>
                ))}
              </div>
            </div>
          </div>
          <div className="col-md-8">
            {selectedApi ? (
              <div className="card border-0 shadow-lg" style={{ borderRadius: 16, background: '#fff' }}>
                <div className="card-header bg-white border-0 d-flex align-items-center justify-content-between" style={{ borderTopLeftRadius: 16, borderTopRightRadius: 16 }}>
                  <div>
                    <span className={`badge bg-primary me-2`} style={{ fontSize: '1rem' }}>{selectedApi.method}</span>
                    <span className="fw-bold" style={{ color: '#2563eb', fontFamily: 'Poppins, Montserrat, Arial, sans-serif' }}>{selectedApi.name}</span>
                  </div>
                  <span className="text-muted" style={{ fontSize: '0.95rem' }}>
                    <i className="fas fa-link me-1"></i>
                    <code style={{ color: '#2563eb' }}>/api/ProductMaster/{selectedApi.endpoint}</code>
                  </span>
                </div>
                <div className="card-body">
                  <div className="mb-3">
                    <div className="fw-semibold mb-1" style={{ color: '#2563eb' }}>
                      <i className="fas fa-info-circle me-2 text-primary"></i>Description
                    </div>
                    <div className="text-muted" style={{ fontSize: '1rem' }}>{selectedApi.description}</div>
                  </div>
                  <div className="mb-3">
                    <div className="fw-semibold mb-1" style={{ color: '#2563eb' }}>
                      <i className="fas fa-code me-2 text-primary"></i>Request Body
                    </div>
                    <textarea
                      className="form-control font-monospace shadow-sm"
                      rows="8"
                      value={requestBody}
                      onChange={(e) => setRequestBody(e.target.value)}
                      style={{ fontSize: '1rem', background: '#f6f7fb', border: '1px solid #e0e0e0', borderRadius: 8 }}
                    />
                  </div>
                  <button
                    className="btn fw-bold shadow-sm"
                    style={{
                      fontSize: '1.1rem',
                      letterSpacing: 1,
                      background: 'linear-gradient(90deg, #2563eb 0%, #60a5fa 100%)',
                      color: '#fff',
                      border: 'none',
                      borderRadius: 8,
                      transition: '0.2s',
                      boxShadow: '0 2px 8px rgba(37,99,235,0.10)'
                    }}
                    onClick={handleSendRequest}
                    disabled={loading || !isAuthenticated}
                    onMouseOver={e => e.currentTarget.style.background = 'linear-gradient(90deg, #60a5fa 0%, #2563eb 100%)'}
                    onMouseOut={e => e.currentTarget.style.background = 'linear-gradient(90deg, #2563eb 0%, #60a5fa 100%)'}
                  >
                    {loading ? (
                      <span className="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
                    ) : (
                      <>
                        <i className="fas fa-paper-plane me-2"></i>
                        Try it out
                      </>
                    )}
                  </button>
                  {error && (
                    <div className="alert alert-danger mt-3 poppins" style={{ fontWeight: 500 }}>
                      <i className="fas fa-exclamation-circle me-2"></i>
                      {error}
                    </div>
                  )}
                  {response && (
                    <div className="mt-3">
                      <div className="fw-semibold mb-1" style={{ color: '#2563eb' }}>
                        <i className="fas fa-reply me-2 text-primary"></i>Response
                      </div>
                      <pre className="bg-light p-3 rounded" style={{ fontFamily: 'Fira Mono, monospace', fontSize: '1rem', border: '1px solid #e0e0e0' }}>
                        <code>{response}</code>
                      </pre>
                    </div>
                  )}
                </div>
              </div>
            ) : (
              <div className="card border-0 shadow-lg d-flex align-items-center justify-content-center" style={{ borderRadius: 16, background: '#fff', minHeight: 400 }}>
                <div className="text-center p-5">
                  <i className="fas fa-book fa-3x text-primary mb-3"></i>
                  <h3 className="fw-bold" style={{ fontFamily: 'Poppins, Montserrat, Arial, sans-serif', color: '#2563eb' }}>RFID API Documentation</h3>
                  <p className="text-muted">Select an API endpoint from the sidebar to view documentation and test the API.</p>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
      {/* Google Fonts for Poppins */}
      <link href="https://fonts.googleapis.com/css2?family=Poppins:wght@400;600&family=Montserrat:wght@500&display=swap" rel="stylesheet" />
    </div>
  );
};

export default Dashboard;
